import React, { useEffect, useState, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

function CallbackPage() {
  const { handleCallback } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [callbackError, setCallbackError] = useState(null);
  const processedRef = useRef(false);

  useEffect(() => {
    if (processedRef.current) return;
    processedRef.current = true;

    const processCallback = async () => {
      try {
        await handleCallback(searchParams);
        navigate('/dashboard', { replace: true });
      } catch (err) {
        console.error('Callback error:', err);
        setCallbackError(err.message);
        setTimeout(() => {
          navigate('/login', { replace: true });
        }, 5000);
      }
    };

    processCallback();
  }, [handleCallback, navigate, searchParams]);

  if (callbackError) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.errorIcon}>❌</div>
          <h2 style={styles.title}>Authentication Failed</h2>
          <p style={styles.errorText}>{callbackError}</p>
          <p style={styles.redirectText}>Redirecting to login page...</p>
          <button
            onClick={() => navigate('/login', { replace: true })}
            style={styles.button}
          >
            Go to Login
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <div style={styles.spinnerContainer}>
          <div style={styles.spinner}></div>
        </div>
        <h2 style={styles.title}>Completing sign-in...</h2>
        <p style={styles.subtitle}>Please wait while we verify your identity.</p>
      </div>

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

